sql:
SELECT genre_id, time_period, trend_score
FROM genre_trends
WHERE trend_type = 'decreasing';

SELECT content_id
FROM content
WHERE runtime = (
  SELECT MIN(runtime)
  FROM content
);

external_knowledge:
- 'popular' refers to content with ratings above the average; 
- 'norm' in this context means the average rating of released content from the USA;
- 'USA movies or shows' are those with 'country' as USA.

sql:
SELECT country, language, AVG(rating) as average_rating 
FROM content 
GROUP BY country, language;

external_knowledge:
- 'glowing reviews' refers to high ratings;
- 'esteemed' implies a high rating standard, greater than 9;
- 'content treasures' metaphorically refers to highly-rated content pieces;
- 'luminous stars' metaphorically refers to the top-rated items;
- 'shine above a rating of 9' means content with a rating greater than 9;
- 'top 10 luminous stars' refers to the top 10 highest-rated items.

sql:
SELECT AVG(rating) AS average_rating
FROM content
WHERE director = 'Christopher Nolan' AND content_type = 'movie';

SELECT COUNT(DISTINCT content_type)
FROM content
WHERE content_type = 'movie' AND rating >= 8.0;

SELECT AVG(rating) AS Average_Rating
FROM content
WHERE director = 'John Doe' AND content_type = 'movie' AND content_status = 'released';

external_knowledge:
- "types of media" refers to genres in the context of this question;
- "last decade" means between 2010 and 2020;
- "favorable reviews" equates to an average rating of at least 6.5;
- "how good were those reviews on average" indicates the average rating for each genre.

sql:
SELECT COUNT(DISTINCT user_id)
FROM content_ratings
WHERE rating_score > 8;

SELECT SUM(duration_watched)
FROM viewing_history
WHERE user_id = 1;
